document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener("click",function(e){const href=this.getAttribute("href");if(href!=="#"&&href!=="#navbarNav"){e.preventDefault();const target=document.querySelector(href);target&&target.scrollIntoView({behavior:"smooth",block:"start"})}})});const navLinks=document.querySelectorAll(".navbar-nav .nav-link"),navbarCollapse=document.querySelector(".navbar-collapse");navLinks.forEach(link=>{link.addEventListener("click",()=>{if(navbarCollapse.classList.contains("show")){new bootstrap.Collapse(navbarCollapse,{toggle:!1}).hide()}})})});